const token = $env.META_INSTAGRAM_ACCESS_TOKEN || $env.META_ACCESS_TOKEN || $env.META_ADS_ACCESS_TOKEN;
const pageId = $env.META_PAGE_ID || $env.INSTAGRAM_PAGE_ID || '112894641702385';
const instagramId = $env.INSTAGRAM_BUSINESS_ACCOUNT_ID || '17841400108793586';
const conversationsLimit = Number($env.INSTAGRAM_DIRECTS_CONVERSATIONS_LIMIT || 50);
const messagesLimit = Number($env.INSTAGRAM_DIRECTS_MESSAGES_LIMIT || 20);

if (!token) {
  throw new Error('Configure META_INSTAGRAM_ACCESS_TOKEN ou META_ACCESS_TOKEN no ambiente do n8n.');
}

return [{
  json: {
    token,
    pageId,
    instagramId,
    conversationsLimit,
    messagesLimit,
    graphVersion: $env.META_GRAPH_VERSION || 'v23.0'
  }
}];

function text(value) {
  return String(value || '').trim();
}

function lower(value) {
  return text(value).toLowerCase();
}

function firstValue(...values) {
  for (const value of values) {
    if (value !== undefined && value !== null && text(value) !== '') return value;
  }
  return null;
}

function isBusinessSender(message) {
  const from = message.from || {};
  const fromId = text(from.id);
  const fromUsername = lower(from.username || from.name);
  const pageId = text($items('Configurar coleta')[0].json.pageId);
  const instagramId = text($items('Configurar coleta')[0].json.instagramId);
  const businessUsername = lower($env.INSTAGRAM_USERNAME || 'fga.jucoutinho');

  return Boolean(
    fromId && (fromId === pageId || fromId === instagramId) ||
    fromUsername === businessUsername ||
    fromUsername === '@' + businessUsername
  );
}

function isRiskText(value) {
  const content = lower(value);
  return /(erro|falha|problema|bug|reclama[cç][aã]o|ruim|incomplet|pl[aá]gio|indevid|link errado|valor errado|pre[cç]o errado|n[aã]o funciona|reembolso|chargeback|cobran[cç]a|devolu[cç][aã]o|cancelar|cancelamento)/.test(content);
}

function isCommercialText(value) {
  const content = lower(value);
  return /(valor|pre[cç]o|matr[ií]cula|inscri[cç][aã]o|link|comprar|compra|pagamento|boleto|pix|cart[aã]o|agenda|consulta|palestra|or[cç]amento|quero|interesse|como funciona|curso|forma[cç][aã]o)/.test(content);
}

function topicFor(value) {
  const content = lower(value);
  if (isRiskText(content)) return 'Risco / Reclamacao';
  if (/(jiu|jitsu|kimono|luta|tatame|faixa)/.test(content)) return 'Jiu Jitsu';
  if (/(fam[ií]lia|filh|m[aã]e|pai|marido|espos|casa|crian[cç]a)/.test(content)) return 'Familia';
  if (/(curso|forma[cç][aã]o|aasi|imers[aã]o|mentoria|aula|alun)/.test(content)) return 'Curso / Formacao';
  if (/(consulta|cl[ií]nica|paciente|audiometria|zumbido|aparelho|audiologia|fono)/.test(content)) return 'Consulta / Clinica';
  if (isCommercialText(content)) return 'Interesse comercial';
  return 'Sem tema definido';
}

function potentialFor(value, wasAnswered) {
  if (isRiskText(value)) return 'alto';
  if (isCommercialText(value)) return 'alto';
  if (!wasAnswered) return 'medio';
  if (text(value)) return 'baixo';
  return 'nao_classificado';
}

function actionFor(value, wasAnswered) {
  if (isRiskText(value)) return 'Priorizar resposta humana, corrigir link/valor se aplicavel e registrar acao tomada.';
  if (!wasAnswered && isCommercialText(value)) return 'Responder com orientacao objetiva, link correto e proximo passo de compra ou atendimento.';
  if (!wasAnswered) return 'Responder ou marcar como analisado apos avaliar o contexto da conversa.';
  return 'Conversa ja respondida; manter monitoramento se houver nova mensagem.';
}

const response = items[0]?.json || {};
const conversations = Array.isArray(response.data) ? response.data : [];
const rows = [];

for (const conversation of conversations) {
  const messages = Array.isArray(conversation.messages?.data) ? conversation.messages.data : [];
  const sorted = [...messages].sort((a, b) => new Date(a.created_time || 0) - new Date(b.created_time || 0));

  for (const message of sorted) {
    if (isBusinessSender(message)) continue;

    const messageText = firstValue(message.message, message.attachments ? '[Anexo recebido]' : null, message.sticker ? '[Figurinha recebida]' : null, '');
    const laterBusinessReply = sorted.some((candidate) => {
      return isBusinessSender(candidate) && new Date(candidate.created_time || 0) > new Date(message.created_time || 0);
    });
    const productTopic = topicFor(messageText);
    const potential = potentialFor(messageText, laterBusinessReply);

    rows.push({
      tenant_name: firstValue($env.PLATAFORMA_TENANT_NAME, 'Juliana Coutinho'),
      account_name: firstValue($env.INSTAGRAM_ACCOUNT_NAME, 'Juliana Coutinho'),
      username: firstValue($env.INSTAGRAM_USERNAME, 'fga.jucoutinho'),
      source: 'direct',
      marketing_type: 'interacao_marketing',
      external_id: firstValue(message.id, conversation.id + '-' + message.created_time),
      profile_username: firstValue(message.from?.username, message.from?.name, message.from?.id),
      profile_name: firstValue(message.from?.name, message.from?.username, message.from?.id),
      message_text: messageText,
      media_id: conversation.id,
      post_id: null,
      post_permalink: null,
      interaction_at: firstValue(message.created_time, conversation.updated_time, new Date().toISOString()),
      status: laterBusinessReply ? 'respondido' : 'novo',
      potential,
      product_topic: productTopic,
      next_action: actionFor(messageText, laterBusinessReply),
      origem: 'n8n_instagram_directs_messages',
      raw_payload: {
        conversation_id: conversation.id,
        conversation_updated_time: conversation.updated_time,
        message,
        participants: conversation.participants || null,
        later_business_reply: laterBusinessReply
      }
    });
  }
}

if (!rows.length) {
  return [{ json: { rows: [], skipped: true, reason: 'Nenhuma mensagem de cliente encontrada nas conversas retornadas.' } }];
}

return [{ json: { rows, count: rows.length } }];

const rows = items[0]?.json?.rows || [];
const batchSize = Number($env.INSTAGRAM_DIRECTS_BATCH_SIZE || 100);

if (!rows.length) {
  return [{ json: { rows: [], skipped: true, reason: items[0]?.json?.reason || 'Sem linhas para importar.' } }];
}

const batches = [];
for (let index = 0; index < rows.length; index += batchSize) {
  batches.push({
    json: {
      rows: rows.slice(index, index + batchSize),
      batch: Math.floor(index / batchSize) + 1,
      total_batches: Math.ceil(rows.length / batchSize),
      total_rows: rows.length
    }
  });
}

return batches;

return [{
  json: {
    ok: true,
    skipped: true,
    reason: $json.reason || 'Sem novas mensagens para importar.'
  }
}];
